SELECT FROM forum_post p LEFT JOIN sys_user u ON p.user_id = u.id LEFT JOIN forum_board b ON p.board_id = b.id LEFT JOIN product pr ON p.product_id = pr.id WHERE p.status = 'NORMAL'
AND ( p.title ILIKE CONCAT('%', #{keyword}, '%') OR p.content ILIKE CONCAT('%', #{keyword}, '%') )
AND p.post_type = #{postType}
AND p.board_id = #{boardId}
ORDER BY p.create_time DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM forum_post p
WHERE p.status = 'NORMAL'

    AND (
        p.title ILIKE CONCAT('%', #{keyword}, '%')
        OR p.content ILIKE CONCAT('%', #{keyword}, '%')
    )


    AND p.post_type = #{postType}


    AND p.board_id = #{boardId}

mapper.update:
UPDATE forum_post
SET view_count = view_count + 1
WHERE id = #{id}

UPDATE forum_post
SET status = 'DELETED',
    update_time = now()
WHERE id = #{id}
  AND user_id = #{userId}
  AND status = 'NORMAL'

mapper.select:
SELECT FROM forum_post p LEFT JOIN sys_user u ON p.user_id = u.id LEFT JOIN forum_board b ON p.board_id = b.id LEFT JOIN product pr ON p.product_id = pr.id WHERE 1 = 1
AND ( p.title ILIKE CONCAT('%', #{keyword}, '%') OR p.content ILIKE CONCAT('%', #{keyword}, '%') OR u.username ILIKE CONCAT('%', #{keyword}, '%') )
AND p.post_type = #{postType}
AND p.status = #{status}
ORDER BY p.create_time DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM forum_post p LEFT JOIN sys_user u ON p.user_id = u.id WHERE 1 = 1
AND ( p.title ILIKE CONCAT('%', #{keyword}, '%') OR p.content ILIKE CONCAT('%', #{keyword}, '%') OR u.username ILIKE CONCAT('%', #{keyword}, '%') )
AND p.post_type = #{postType}
AND p.status = #{status}

SELECT c.id, c.post_id, c.user_id, c.parent_id, c.content, c.status, c.create_time, u.username, u.avatar_url, p.title AS post_title FROM forum_comment c LEFT JOIN sys_user u ON c.user_id = u.id LEFT JOIN forum_post p ON c.post_id = p.id WHERE 1 = 1
AND ( c.content ILIKE CONCAT('%', #{keyword}, '%') OR u.username ILIKE CONCAT('%', #{keyword}, '%') OR p.title ILIKE CONCAT('%', #{keyword}, '%') )
AND c.status = #{status}
ORDER BY c.create_time DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM forum_comment c LEFT JOIN sys_user u ON c.user_id = u.id LEFT JOIN forum_post p ON c.post_id = p.id WHERE 1 = 1
AND ( c.content ILIKE CONCAT('%', #{keyword}, '%') OR u.username ILIKE CONCAT('%', #{keyword}, '%') OR p.title ILIKE CONCAT('%', #{keyword}, '%') )
AND c.status = #{status}

